/**
 * Reads `.env` at the project root (see .env.example) and writes
 * src/shared/firebaseConfig.generated.ts — a plain TS module with the
 * actual values baked in as literals. This runs at BUILD time (developer
 * machine), same spirit as prepare-runtime.js: the end user's installed
 * app never reads a .env file (Program Files is read-only, and shipping a
 * loose .env next to the exe is fragile) — the config is compiled in.
 *
 * Safe to commit the generated file's ABSENCE of real values (this script
 * is idempotent and .gitignore excludes the generated file) but the file
 * itself is gitignored on purpose: whoever builds a release fills in their
 * own .env locally, exactly like the website does for its own env vars.
 */
const fs = require("node:fs");
const path = require("node:path");

const ENV_PATH = path.join(__dirname, "..", ".env");
const OUT_PATH = path.join(__dirname, "..", "src", "shared", "firebaseConfig.generated.ts");

function parseEnvFile(text) {
  const out = {};
  for (const rawLine of text.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line || line.startsWith("#")) continue;
    const eq = line.indexOf("=");
    if (eq === -1) continue;
    const key = line.slice(0, eq).trim();
    let value = line.slice(eq + 1).trim();
    if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }
    out[key] = value;
  }
  return out;
}

function main() {
  const env = fs.existsSync(ENV_PATH) ? parseEnvFile(fs.readFileSync(ENV_PATH, "utf8")) : {};

  const config = {
    apiKey: env.FIREBASE_API_KEY ?? "",
    authDomain: env.FIREBASE_AUTH_DOMAIN ?? "",
    projectId: env.FIREBASE_PROJECT_ID ?? "",
    storageBucket: env.FIREBASE_STORAGE_BUCKET ?? "",
    messagingSenderId: env.FIREBASE_MESSAGING_SENDER_ID ?? "",
    appId: env.FIREBASE_APP_ID ?? "",
  };
  const siteApiBase = env.SITE_API_BASE || "https://manim-std.vercel.app";
  const updateRepo = env.UPDATE_REPO ?? "";

  const configured = Boolean(config.apiKey && config.projectId && config.appId);
  if (!configured) {
    console.warn(
      "[generate-firebase-config] No .env found (or it's incomplete) — building WITHOUT Firebase login/notifications. " +
      "Copy .env.example to .env and fill in your Firebase web config to enable them.",
    );
  }

  const contents = `// AUTO-GENERATED by scripts/generate-firebase-config.js — do not edit by
// hand, and do not commit real values here (this file is gitignored).
// Re-run \`npm run generate-firebase-config\` after editing .env.

export const FIREBASE_CONFIG = ${JSON.stringify(config, null, 2)} as const;

export const SITE_API_BASE: string = ${JSON.stringify(siteApiBase)};

export const UPDATE_REPO: string = ${JSON.stringify(updateRepo)};

export function isFirebaseConfigured(): boolean {
  return Boolean(FIREBASE_CONFIG.apiKey && FIREBASE_CONFIG.projectId && FIREBASE_CONFIG.appId);
}
`;

  fs.mkdirSync(path.dirname(OUT_PATH), { recursive: true });
  fs.writeFileSync(OUT_PATH, contents, "utf8");
  console.log(`[generate-firebase-config] wrote ${path.relative(process.cwd(), OUT_PATH)} (configured=${configured})`);
}

main();
